// Récupère le paramètre 'days' (0 = aujourd'hui, 1 = demain, etc.)
const days = $input.first().json.query?.days || $input.first().json.body?.days || 0;
const daysOffset = parseInt(days) || 0;

// Calcule la date cible
const targetDate = new Date();
targetDate.setDate(targetDate.getDate() + daysOffset);

// Format YYYY-MM-DD pour l'URL
const year = targetDate.getFullYear();
const month = String(targetDate.getMonth() + 1).padStart(2, '0');
const day = String(targetDate.getDate()).padStart(2, '0');
const formattedDate = `${year}-${month}-${day}`;

return [{
  json: {
    daysOffset: daysOffset,
    targetDate: targetDate.toISOString(),
    formattedDate: formattedDate,
    displayDate: targetDate.toLocaleDateString('fr-FR', { weekday: 'long', day: 'numeric', month: 'long' })
  }
}];

